+        let wc = tree
+            .create_child(root, RegionKind::WriteCoordinator, Cx::new())
+            .expect("wc");
+        let ss = tree
+            .create_child(root, RegionKind::SymbolStore, Cx::new())
+            .expect("ss");
+        let repl = tree
+            .create_child(root, RegionKind::Replication, Cx::new())
+            .expect("repl");
+        let gc = tree
+            .create_child(root, RegionKind::CheckpointGc, Cx::new())
